 1	import React, { FC } from 'react';
 2	
 3	import { IngressModel, NamespaceModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { IoK8sApiNetworkingV1Ingress } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import {
 6	  getGroupVersionKindForModel,
 7	  ResourceLink,
 8	  Timestamp,
 9	  useAccessReview,
10	  useAnnotationsModal,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import { DetailsItem } from '@utils/components/DetailsItem/DetailsItem';
13	import { LabelList } from '@utils/components/DetailsItem/LabelList';
14	import { OwnerReferences } from '@utils/components/OwnerReference/owner-references';
15	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
16	import {
17	  getCreationTimestamp,
18	  getLabels,
19	  getName,
20	  getNamespace,
21	  getUID,
22	} from '@utils/resources/shared';
23	
24	import TLSCert from './TLSCert';
25	
26	type IngressDetailsSectionProps = {
27	  ingress: IoK8sApiNetworkingV1Ingress;
28	};
29	
30	const IngressDetailsSection: FC<IngressDetailsSectionProps> = ({ ingress }) => {
31	  const { t } = useNetworkingTranslation();
32	  const annotationsModalLauncher = useAnnotationsModal(ingress);
33	
34	  const [canUpdate] = useAccessReview({
35	    group: IngressModel?.apiGroup,
36	    name: getName(ingress),
37	    namespace: getNamespace(ingress),
38	    resource: IngressModel?.plural,
39	    verb: 'patch',
40	  });
41	
42	  const ingressNamespace = getNamespace(ingress);
43	
44	  return (
45	    <>
46	      <DetailsItem label={t('Name')} obj={ingress} path="metadata.name" />
47	      {ingressNamespace && (
48	        <DetailsItem label={t('Namespace')} obj={ingress} path="metadata.namespace">
49	          <ResourceLink
50	            groupVersionKind={getGroupVersionKindForModel(NamespaceModel)}
51	            name={getName(ingress)}
52	            namespace={ingressNamespace}
53	            title={getUID(ingress)}
54	          />
55	        </DetailsItem>
56	      )}
57	      <DetailsItem
58	        canEdit={canUpdate}
59	        editAsGroup
60	        label={t('Labels')}
61	        obj={ingress}
62	        onEdit={annotationsModalLauncher}
63	        path="metadata.labels"
64	        valueClassName="details-item__value--labels"
65	      >
66	        <LabelList
67	          groupVersionKind={getGroupVersionKindForModel(IngressModel)}
68	          labels={getLabels(ingress)}
69	        />
70	      </DetailsItem>
71	      <DetailsItem label={t('TLS certificate')}>
72	        <TLSCert ingress={ingress} />
73	      </DetailsItem>
74	      <DetailsItem label={t('Created at')} obj={ingress} path="metadata.creationTimestamp">
75	        <Timestamp timestamp={getCreationTimestamp(ingress)} />
76	      </DetailsItem>
77	      <DetailsItem label={t('Owner')} obj={ingress} path="metadata.ownerReferences">
78	        <OwnerReferences resource={ingress} />
79	      </DetailsItem>
80	    </>
81	  );
82	};
83	
84	export default IngressDetailsSection;

